module serial2parallel(
    input clk,
    input rst_n,
    input din_serial,
    input din_valid,
    output reg [7:0] dout_parallel,
    output reg dout_valid
);

reg [3:0] count;
reg [7:0] shift_reg;

always @(posedge clk) begin
    if (!rst_n) begin
        count <= 0;
        shift_reg <= 0;
        dout_parallel <= 0;
        dout_valid <= 0;
    end else if (din_valid) begin
        if (count == 4'd8) begin
            shift_reg <= {shift_reg[6:0], din_serial};
            count <= 0;
            dout_parallel <= shift_reg;
            dout_valid <= 1'b1;
        end else begin
            shift_reg <= {shift_reg[6:0], din_serial};
            count <= count + 1;
            dout_valid <= 1'b0;
        end
    end
end

endmodule

module div_16bit(
    input clk,
    input rst,
    input sign,
    input [15:0] dividend,
    input [15:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output reg [15:0] result
);

    // Define the parameter values
    parameter IDLE = 3'd0;
    parameter START = 3'd1;
    parameter SUB = 3'd2;
    parameter SEL = 3'd3;
    parameter SHIFT = 3'd4;
    parameter DONE = 3'd5;

    // Define the registers
    reg [2:0] state, next_state;
    reg [3:0] cnt;
    reg start_cnt;
    reg [7:0] neg_divisor;
    reg [15:0] sr;

    // Define the wires
    wire [7:0] sub_result;
    wire [7:0] mux_result;
    wire [7:0] add_result;
    wire [7:0] abs_dividend;
    wire [7:0] abs_divisor;
    wire cout1;
    wire cout2;
    wire cout3;
    wire cout4;
    wire cout5;
    wire cout6;
    wire cout7;
    wire cout8;
    wire carry;

    // Get the absolute value of the dividend
    assign abs_dividend = (sign & dividend[7]) ? ~dividend + 1'b1 : dividend;

    // Get the absolute value of the divisor
    assign abs_divisor = (sign & divisor[7]) ? ~divisor + 1'b1 : divisor;

    // Update the result when res_valid is high and res_ready is low
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            res_valid <= 1'b0;
        end else if (state == DONE) begin
            res_valid <= 1'b1;
        end else if (res_valid & res_ready) begin
            res_valid <= 1'b0;
        end
    end

    // Update the result
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            result <= 16'b0;
        end else if (state == DONE) begin
            result <= {sr[7:0], sr[15:8]};
        end
    end

    // Update the shift register
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            sr <= 16'b0;
        end else if (opn_valid & ~res_valid) begin
            sr <= {abs_dividend, 8'b0};
        end else if (start_cnt) begin
            if (cnt == 4'b1000) begin
                sr <= {1'b0, sr[15:1]};
            end else begin
                sr <= {carry, sr[15:1]};
            end
        end
    end

    // Update the counter and start_cnt
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            cnt <= 4'b0;
            start_cnt <= 1'b0;
        end else if (opn_valid & ~res_valid) begin
            cnt <= 4'b1;
            start_cnt <= 1'b1;
        end else if (start_cnt) begin
            if (cnt == 4'b1000) begin
                cnt <= 4'b0;
                start_cnt <= 1'b0;
            end else begin
                cnt <= cnt + 1'b1;
            end
        end
    end

    // Update the neg_divisor
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            neg_divisor <= 8'b0;
        end else if (opn_valid & ~res_valid) begin
            neg_divisor <= ~abs_divisor + 1'b1;
        end
    end

    // Update the subtraction
    assign sub_result = sr[7:0] + neg_divisor;

    // Update the mux
    assign mux_result = (sub_result[7] == 1'b1) ? sr[7:0] : sub_result;

    // Update the carry
    assign carry = (sub_result[7] == 1'b1) ? 1'b0 : 1'b1;

    // FSM state update
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= IDLE;
        end else begin
            state <= next_state;
        end
    end

    // FSM next state logic
    always @(*) begin
        case (state)
            IDLE: begin
                if (opn_valid) begin
                    next_state = START;
                end else begin
                    next_state = IDLE;
                end
            end
            START: begin
                next_state = SUB;
            end
            SUB: begin
                next_state = SEL;
            end
            SEL: begin
                next_state = SHIFT;
            end
            SHIFT: begin
                if (cnt == 4'b1000) begin
                    next_state = DONE;
                end else begin
                    next_state = SUB;
                end
            end
            DONE: begin
                next_state = IDLE;
            end
            default: begin
                next_state = IDLE;
            end
        endcase
    end
endmodule

module width_8to16(
    input clk,
    input rst_n,
    input valid_in,
    input [7:0] data_in,
    output reg valid_out,
    output reg [15:0] data_out
);
// flag register for FSM
reg flag_reg;
// register to lock the first valid input data
reg [7:0] data_lock;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        data_out <= 16'b0;
    end else begin
        if (valid_in && flag_reg == 1'b0) begin
            data_lock <= data_in;
        end else if (valid_in && flag_reg == 1'b1) begin
            data_out <= {data_lock, data_in};
        end
    end
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        valid_out <= 1'b0;
    end else begin
        if (valid_in && flag_reg == 1'b0) begin
            valid_out <= 1'b0;
        end else if (valid_in && flag_reg == 1'b1) begin
            valid_out <= 1'b1;
        end
    end
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        flag_reg <= 1'b0;
    end else begin
        if (valid_in && flag_reg == 1'b0) begin
            flag_reg <= 1'b1;
        end else if (valid_in && flag_reg == 1'b1) begin
            flag_reg <= 1'b0;
        end
    end
end
endmodule

module traffic_light(
    input rst_n,
    input clk,
    input pass_request,
    output reg red,
    output reg yellow,
    output reg green,
    output [7:0] clock
);

    reg [7:0] timer;
    reg [1:0] state;
    parameter IDLE = 2'b00, GREEN = 2'b01, YELLOW = 2'b10, RED = 2'b11;

    assign clock = timer;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state <= IDLE;
            timer <= 0;
            red <= 0;
            yellow <= 0;
            green <= 1;
        end else begin
            case (state)
                IDLE: begin
                    if (pass_request) begin
                        state <= RED;
                        timer <= 8'd10;
                    end else begin
                        state <= GREEN;
                        timer <= 8'd60;
                    end
                    red <= 0;
                    yellow <= 0;
                    green <= 1;
                end
                GREEN: begin
                    if (timer == 8'd10) begin
                        state <= YELLOW;
                        timer <= 8'd5;
                    end else begin
                        timer <= timer - 1;
                    end
                    red <= 0;
                    yellow <= 0;
                    green <= 1;
                end
                YELLOW: begin
                    if (timer == 8'd5) begin
                        state <= RED;
                        timer <= 8'd10;
                    end else begin
                        timer <= timer - 1;
                    end
                    red <= 0;
                    yellow <= 1;
                    green <= 0;
                end
                RED: begin
                    if (timer == 8'd10) begin
                        state <= GREEN;
                        timer <= 8'd60;
                    end else begin
                        timer <= timer - 1;
                    end
                    red <= 1;
                    yellow <= 0;
                    green <= 0;
                end
            endcase
        end
    end

endmodule

module multi_16bit(
    input clk,
    input rst_n,
    input start,
    input [15:0] ain,
    input [15:0] bin,
    output [31:0] yout,
    output done
);
    reg [3:0] i;
    reg [15:0] areg,breg;
    reg [31:0] yout_r;
    reg done_r;
    assign yout=yout_r;
    assign done=done_r;
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n)begin
            i<=4'd0;
        end
        else if (start&&i<4'd17)begin
            i<=i+1'b1;
        end
        else begin
            i<=4'd0;
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n)begin
            done_r<=1'b0;
        end
        else if (i==4'd16)begin
            done_r<=1'b1;
        end
        else if (i==4'd17)begin
            done_r<=1'b0;
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n)begin
            areg<=16'b0;
            breg<=16'b0;
            yout_r<=32'b0;
        end
        else if (i==4'd0&&start)begin
            areg<=ain;
            breg<=bin;
        end
        else if (i>4'd0&&i<4'd17)begin
            if (areg[i-1'b1]) begin
                yout_r<=yout_r+(breg<<<(i-1'b1));
            end
        end
        else begin
            yout_r<=yout_r;
        end
    end
endmodule

