module parallel2serial(
    input clk,
    input rst_n,
    input [3:0] d,
    output valid_out,
    output dout
);

reg [3:0] shift_reg;
reg [1:0] count;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        shift_reg <= 4'b0;
        count <= 2'b0;
    end
    else begin
        if (count == 2'b11) begin
            shift_reg <= d;
            count <= 2'b0;
        end
        else begin
            shift_reg <= {shift_reg[2:0], 1'b0};
            count <= count + 1'b1;
        end
    end
end

assign valid_out = (count == 2'b11) ? 1'b1 : 1'b0;
assign dout = (count == 2'b11) ? shift_reg[3] : 1'b0;

endmodule

module div_16bit(
    input [15:0] A,
    input [7:0] B,
    output [15:0] result,
    output [15:0] odd
);

    reg [15:0] dividend;
    reg [7:0] divisor;
    reg [15:0] quotient;
    reg [15:0] remainder;

    always @(*) begin
        dividend = A[15:8];
        divisor = B;
        quotient = 16'b0;
        remainder = 16'b0;

        if (dividend >= divisor) begin
            quotient = 16'b1;
            remainder = dividend - divisor;
        end
        else begin
            quotient = 16'b0;
            remainder = dividend;
        end
    end

    assign result = {8'b0, quotient[7:0]};
    assign odd = remainder;

endmodule

module multi_8bit(
    input [7:0] A,
    input [7:0] B,
    output [15:0] product
);
    reg [15:0] result;
    integer i;

    always @(*) begin
        result = 0;
        for (i = 0; i < 8; i = i + 1) begin
            if (B[i]) begin
                result = result + (A << i);
            end
        end
    end

    assign product = result;
endmodule

module fsm(
    input IN,
    input CLK,
    input RST,
    output reg MATCH
);

reg [4:0] state;

localparam IDLE = 5'b00001,
          STATE1 = 5'b00010,
          STATE2 = 5'b00100,
          STATE3 = 5'b01000,
          STATE4 = 5'b10000;

always @(posedge CLK or negedge RST) begin
    if (!RST) begin
        state <= IDLE;
        MATCH <= 1'b0;
    end
    else begin
        case (state)
            IDLE: begin
                if (IN == 1'b1)
                    state <= STATE1;
                else
                    state <= IDLE;
                MATCH <= 1'b0;
            end
            STATE1: begin
                if (IN == 1'b0)
                    state <= STATE2;
                else
                    state <= STATE1;
                MATCH <= 1'b0;
            end
            STATE2: begin
                if (IN == 1'b0)
                    state <= STATE3;
                else
                    state <= IDLE;
                MATCH <= 1'b0;
            end
            STATE3: begin
                if (IN == 1'b1)
                    state <= STATE4;
                else
                    state <= STATE1;
                MATCH <= 1'b0;
            end
            STATE4: begin
                if (IN == 1'b1)
                    state <= IDLE;
                else
                    state <= STATE2;
                MATCH <= 1'b1;
            end
            default: begin
                state <= IDLE;
                MATCH <= 1'b0;
            end
        endcase
    end
end

endmodule

module freq_div(
    input CLK_in,
    input RST,
    output reg CLK_50,
    output reg CLK_10,
    output reg CLK_1
);

reg [2:0] counter_50;
reg [3:0] counter_10;
reg [6:0] counter_1;

always @(posedge CLK_in or negedge RST) begin
    if (!RST) begin
        counter_50 <= 0;
        counter_10 <= 0;
        counter_1 <= 0;
        CLK_50 <= 0;
        CLK_10 <= 0;
        CLK_1 <= 0;
    end else begin
        // 50MHz clock generation
        if (counter_50 == 4) begin
            counter_50 <= 0;
            CLK_50 <= ~CLK_50;
        end else begin
            counter_50 <= counter_50 + 1;
        end

        // 10MHz clock generation
        if (counter_10 == 9) begin
            counter_10 <= 0;
            CLK_10 <= ~CLK_10;
        end else begin
            counter_10 <= counter_10 + 1;
        end

        // 1MHz clock generation
        if (counter_1 == 99) begin
            counter_1 <= 0;
            CLK_1 <= ~CLK_1;
        end else begin
            counter_1 <= counter_1 + 1;
        end
    end
end

endmodule

module alu(
    input [31:0] a,
    input [31:0] b,
    input [5:0] aluc,
    output [31:0] r,
    output zero,
    output carry,
    output negative,
    output overflow,
    output flag
);

    // Internal signals
    wire [31:0] result;
    wire [31:0] add_result;
    wire [31:0] sub_result;
    wire [31:0] and_result;
    wire [31:0] or_result;
    wire [31:0] xor_result;
    wire [31:0] sl_result;
    wire [31:0] sr_result;
    wire [31:0] sra_result;
    wire [31:0] lui_result;
    wire [31:0] adder_result;
    wire [31:0] subtractor_result;
    wire adder_carry;
    wire subtractor_carry;
    wire overflow_flag;
    wire zero_flag;
    wire negative_flag;
    wire carry_flag;
    wire flag_flag;

    // Arithmetic and logic operations
    assign and_result = a & b;
    assign or_result = a | b;
    assign xor_result = a ^ b;
    assign and_result = a & b;
    assign or_result = a | b;
    assign xor_result = a ^ b;
    assign sl_result = a << b[4:0];
    assign sr_result = a >> b[4:0];
    assign sra_result = $signed(a) >>> b[4:0];
    assign lui_result = {b[15:0], 16'b0};

    // Adder
    assign {adder_carry, adder_result} = a + b;
    assign overflow_flag = (a[31] == b[31]) && (adder_result[31] != a[31]);
    assign zero_flag = (adder_result == 32'b0);
    assign negative_flag = (adder_result[31] == 1'b1);
    assign carry_flag = (adder_carry == 1'b1);

    // Subtractor
    assign {subtractor_carry, subtractor_result} = a - b;
    assign zero_flag = (subtractor_result == 32'b0);
    assign negative_flag = (subtractor_result[31] == 1'b1);
    assign carry_flag = (subtractor_carry == 1'b1);

    // ALU control logic
    assign r = (aluc == 6'b000000) ? adder_result : // Add
               (aluc == 6'b000001) ? subtractor_result : // Subtract
               (aluc == 6'b000010) ? and_result : // And
               (aluc == 6'b000011) ? or_result : // Or
               (aluc == 6'b000100) ? xor_result : // Xor
               (aluc == 6'b000101) ? sl_result : // Shift left
               (aluc == 6'b000110) ? sr_result : // Shift right
               (aluc == 6'b000111) ? sra_result : // Shift right arithmetic
               (aluc == 6'b001000) ? lui_result : // Load upper immediate
               32'b0;

    assign zero = zero_flag;
    assign carry = carry_flag;
    assign negative = negative_flag;
    assign overflow = overflow_flag;
    assign flag = flag_flag;

endmodule

module edge_detect(
    input clk,
    input rst_n,
    input a,
    output reg rise,
    output reg down,
    output reg rise,
    output reg rise,
    output reg down,
    output reg down
);

    reg a_prev;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            a_prev <= 1'b0;
            rise <= 1'b0;
            down <= 1'b0;
        end
        else begin
            a_prev <= a;
            rise <= 1'b0;
            down <= 1'b0;

            if (a_prev == 1'b0 && a == 1'b1) begin
                rise <= 1'b1;
            end
            else if (a_prev == 1'b1 && a == 1'b0) begin
                down <= 1'b1;
            end
        end
    end

endmodule

