module multi_pipe_4bit(
    input clk,
    input rst_n,
    input [3:0] mul_a,
    input [3:0] mul_b,
    output reg [7:0] mul_out
);

parameter size = 4;

reg [size-1:0] reg_a, reg_b;
reg [2*size-1:0] reg_s1, reg_s2, reg_s3, reg_s4;
reg [2*size-1:0] reg_sum;
wire [size-1:0] a_and_b;
wire [2*size-1:0] a_shift;
wire [2*size-1:0] adder_out;
wire cout;

// Input and output
always @(*) begin
    reg_a = mul_a;
    reg_b = mul_b;
end

assign a_and_b = reg_a & reg_b;
assign a_shift = reg_a;

// Multiplier
genvar i;
generate
    for (i = 0; i < size; i = i + 1) begin : gen_for_mux
        assign reg_s1[i +: size + 1] = a_and_b[i] ? {{size{i'd0}}, a_and_b[i]} : {size{i'd0}};
        assign a_shift[i +: size + 1] = reg_s1[i +: size + 1] << i;
    end
endgenerate

// Adder
assign adder_out = reg_s2 + reg_s3;
assign cout = adder_out[2*size-1];

// Pipeline registers
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        reg_s2 <= 'd0;
        reg_s3 <= 'd0;
    end else begin
        reg_s2 <= reg_s1;
        reg_s3 <= reg_s2;
    end
end

// Output
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        reg_s4 <= 'd0;
        mul_out <= 'd0;
    end else begin
        reg_s4 <= adder_out;
        mul_out <= reg_s4[7:0];
    end
end

endmodule

module calendar(
    input CLK,
    input RST,
    output reg [5:0] Hours,
    output reg [5:0] Mins,
    output reg [5:0] Secs
);
// Get current time
wire [5:0] cur_segs = Secs;
wire [5:0] cur_mins = Mins;
wire [5:0] cur_hours = Hours;
// Increment Segs
wire [5:0] next_segs = (cur_segs == 59) ? 0 : cur_segs + 1;
// Increment Mins if Segs == 59
wire [5:0] next_mins = (cur_segs == 59) ? (cur_mins == 59 ? 0 : cur_mins + 1) : cur_mins;
// Increment Hours if Segs == 59 and Mins == 59
wire [5:0] next_hours = (cur_segs == 59 && cur_mins == 59) ? (cur_hours == 23 ? 0 : cur_hours + 1) : cur_hours;
always @(posedge CLK or posedge RST) begin
    if (RST) begin
        Secs <= 6'b0;
    end else begin
        Secs <= next_segs;
    end
end
always @(posedge CLK or posedge RST) begin
    if (RST) begin
        Mins <= 6'b0;
    end else begin
        Mins <= next_mins;
    end
end
always @(posedge CLK or posedge RST) begin
    if (RST) begin
        Hours <= 6'b0;
    end else begin
        Hours <= next_hours;
    end
end
endmodule

