module TopModule #(parameter WIDTH = 8, parameter DEPTH = 16) (
    input wclk, rclk, rstn, winc, rinc,
    input [WIDTH-1:0] wdata,
    output wfull, rempty,
    output [WIDTH-1:0] rdata
);
// Control logic for write and read operations
wire wen, ren;
wire [$clog2(DEPTH)-1:0] waddr, raddr;
// Write pointer and read pointer
reg [$clog2(DEPTH)-1:0] waddr_bin, raddr_bin;
reg [$clog2(DEPTH):0] wptr, rptr;
reg [$clog2(DEPTH):0] wptr_buff, rptr_buff;
// Write enable and read enable
assign wen = winc & ~wfull;
assign ren = rinc & ~rempty;
// Dual-port RAM
wire [WIDTH-1:0] rdata_w;
reg [WIDTH-1:0] wdata_w;
assign rdata = rempty ? 0 : rdata_w;
always @(*) begin
    wdata_w = wdata;
end
// Write address and read address
assign waddr = waddr_bin;
assign raddr = raddr_bin;
// Dual-port RAM instance
dual_port_RAM #(.WIDTH(WIDTH), .DEPTH(DEPTH)) dual_port_RAM_inst (
    .wclk(wclk), .wenc(wen), .waddr(waddr), .wdata(wdata_w),
    .rclk(rclk), .renc(ren), .raddr(raddr), .rdata(rdata_w)
);
// Write pointer buffer
always @(posedge wclk or negedge rstn) begin
    if (~rstn) begin
        wptr_buff <= 0;
    end else begin
        wptr_buff <= wptr;
    end
end
// Read pointer buffer
always @(posedge rclk or negedge rstn) begin
    if (~rstn) begin
        rptr_buff <= 0;
    end else begin
        rptr_buff <= rptr;
    end
end
// Full and empty signals
assign wfull = (wptr_buff[$clog2(DEPTH)] != rptr_buff[$clog2(DEPTH)] && wptr_buff[$clog2(DEPTH)-1:0] == rptr_buff[$clog2(DEPTH)-1:0]);
assign rempty = (rptr == wptr);
// Write address binary logic
always @(posedge wclk or negedge rstn) begin
    if (~rstn) begin
        waddr_bin <= 0;
    end else if (winc) begin
        if (waddr_bin == DEPTH-1) begin
            waddr_bin <= 0;
        end else begin
            waddr_bin <= waddr_bin + 1;
        end
    end
end
// Read address binary logic
always @(posedge rclk or negedge rstn) begin
    if (~rstn) begin
        raddr_bin <= 0;
    end else if (rinc) begin
        if (raddr_bin == DEPTH-1) begin
            raddr_bin <= 0;
        end else begin
            raddr_bin <= raddr_bin + 1;
        end
    end
end
// Write pointer Gray code logic
always @(posedge wclk or negedge rstn) begin
    if (~rstn) begin
        wptr <= 0;
    end else if (winc) begin
        if (wptr == DEPTH-1) begin
            wptr <= 0;
        end else begin
            wptr <= wptr + 1;
        end
    end
end
// Read pointer Gray code logic
always @(posedge rclk or negedge rstn) begin
    if (~rstn) begin
        rptr <= 0;
    end else if (rinc) begin
        if (rptr == DEPTH-1) begin
            rptr <= 0;
        end else begin
            rptr <= rptr + 1;
        end
    end
end
endmodule

module adder_32bit(
    input [32:1] A,
    input [32:1] B,
    output [32:1] S,
    output C32
);

    wire [32:0] carry;
    assign carry[0] = 0;

    genvar i;
    generate
        for (i = 1; i < 33; i = i + 1) begin
            wire p, g;
            assign p = A[i] ^ B[i];
            assign g = A[i] & B[i];
            assign carry[i] = g | (p & carry[i-1]);
            assign S[i] = p ^ carry[i-1];
        end
    endgenerate

    assign C32 = carry[32];

endmodule

module signal_generator(
    input clk,
    input rst_n,
    output [4:0] wave
);

reg [4:0] wave_reg;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        wave_reg <= 5'd0;
    end else begin
        if (wave_reg == 5'd31) begin
            wave_reg <= 5'd30;
        end else if (wave_reg == 5'd0) begin
            wave_reg <= 5'd1;
        end else if (wave_reg[0] == 1'b0) begin
            wave_reg <= wave_reg + 5'd1;
        end else begin
            wave_reg <= wave_reg - 5'd1;
        end
    end
end

assign wave = wave_reg;

endmodule

module adder_pipe_64bit(
    input clk,
    input rst_n,
    input i_en,
    input [63:0] adda,
    input [63:0] addb,
    output reg [64:0] result,
    output reg o_en
);

    reg [63:0] adda_reg, addb_reg;
    reg i_en_reg;
    reg [64:0] sum_reg;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            adda_reg <= 64'b0;
            addb_reg <= 64'b0;
            i_en_reg <= 1'b0;
            sum_reg <= 65'b0;
            result <= 65'b0;
            o_en <= 1'b0;
        end else begin
            adda_reg <= adda;
            addb_reg <= addb;
            i_en_reg <= i_en;
            sum_reg <= adda_reg + addb_reg;
            result <= sum_reg;
            o_en <= i_en_reg;
        end
    end

endmodule

